/**
 * @credit https://github.com/piotrwitek/utility-types
 */
type TPrimitive =
  | string
  | number
  | bigint
  | boolean
  | symbol
  | null
  | undefined;

/**
 * @credit https://github.com/sindresorhus/type-fest
 */
type TJsonPrimitive = string | number | boolean | null;

/**
 * @credit https://github.com/piotrwitek/utility-types
 */
type TFalsy = false | "" | 0 | null | undefined;

/**
 * @credit https://github.com/piotrwitek/utility-types
 */
type TNullish = null | undefined;

type TPropertyName = string | number | symbol;

/**
 * @credit https://github.com/piotrwitek/utility-types
 */
type TNonUndefined<A> = A extends undefined ? never : A;

/**
 * Dictionaries are "jsonifiable" object ie with non-cyclic values and "finite" values
 */

/**
 * @credit https://github.com/DefinitelyTyped/DefinitelyTyped/tree/master/types/lodash
 */
type TDictionary<T extends TDictionaryValue = TDictionaryValue> = {
  [key: string]: T;
};

type TJsonDictionary<T extends TJsonValue = TJsonValue> = {
  [key: string]: T;
};

/**
 * @credit https://github.com/DefinitelyTyped/DefinitelyTyped/tree/master/types/lodash
 */
type TNumericDictionary<T extends TDictionaryValue = TDictionaryValue> =
  {
    [key: number]: T;
  };
type TNumericJsonDictionary<T extends TJsonValue = TJsonValue> = {
  [key: number]: T;
};

type StringHash = TDictionary<string>;

type TJsonObject = { [Key in string]: TJsonValue } & {
  [Key in string]?: TJsonValue | undefined;
};

type TJsonArray = TJsonValue[];

type TJsonValue = TJsonPrimitive | TJsonObject | TJsonArray;

type TDictionaryArray = TDictionaryValue[];
type TDictionaryValue = TJsonPrimitive | object | TDictionaryArray;

/**
 * emptyObjectSymbol
 * ---
 * Un symbole unique utilisé comme clé pour le type EmptyObject.
 * Doit être exporté explicitement pour être inclus dans le bundle de types.
 */
declare const emptyObjectSymbol: unique symbol;

// export type TEmptyObjectSymbol = typeof emptyObjectSymbol;

type EmptyObject = { [emptyObjectSymbol]?: never };

/**
Returns a `boolean` for whether the type is strictly equal to an empty plain object, the `{}` value.
@example
```
import type {IsEmptyObject} from 'type-fest';
type Pass = IsEmptyObject<{}>; //=> true
type Fail = IsEmptyObject<[]>; //=> false
type Fail = IsEmptyObject<null>; //=> false
```
@see EmptyObject
@category Object
*/
type IsEmptyObject<T> = T extends EmptyObject ? true : false;

type TPropertyNameByType<T extends object, ValueType> = {
  [K in keyof T]-?: TNonUndefined<T[K]> extends ValueType ? K : never;
}[keyof T];

type RequiredFieldsOnly<T> = {
  [K in keyof T[K] extends Required<T>[K] ? K : never]: T[K];
};

/**
 * TPropertyNameByNotType<T, ValueType>
 * -------
 * From object `T` get union type of all the properties that are NOT of type `ValueType`
 *
 * @example
 * ```
 * const obj = {
 *  name: "koala",
 *  sayHello() {
 *    return "grmmm";
 *  },
 *  isDangerous: false
 * };
 * type TObjFunctionPropertyNames = PropertyNameByNotType<typeof obj, boolean>;
 * // Expect: "name" | "sayHello"
 * ```
 */
type TPropertyNameByNotType<T extends object, ValueType> = {
  [K in keyof T]-?: TNonUndefined<T[K]> extends ValueType ? never : K;
}[keyof T];

/**
 * TFunctionPropertyNames<T>
 * -------
 * From object `T` get union type of all the properties that are functions
 *
 * @example
 * ```
 * const obj = {
 *  name: "koala",
 *  sayHello() {
 *    return "grmmm";
 *  }
 * };
 * type TObjFunctionPropertyNames = FunctionPropertyNames<typeof obj>;
 * // Expect: "sayHello"
 * ```
 */
type TFunctionPropertyNames<T extends object> = TPropertyNameByType<
  T,
  Function
>;

/**
 * TNonFunctionPropertyNames<T>
 * ------
 * From object `T`, get union type of all the properties that are NOT functions
 *
 * @example
 * ```
 * const obj = {
 *  name: "koala",
 *  sayHello() {
 *    return "grmmm";
 *  }
 * };
 * type TObjFunctionPropertyNames = NonFunctionPropertyNames<typeof obj>;
 * // Expect: "name"
 * ```
 */
// export type NonFunctionPropertyNames<T extends object> = {
//   [K in keyof T]-?: NonUndefined<T[K]> extends Function ? never : K;
// }[keyof T];
type TNonFunctionPropertyNames<T extends object> =
  TPropertyNameByNotType<T, Function>;

/**
 * TPropertyNames<T>
 * ---------
 * From `T` get union type of name of all the properties
 *
 * @credit https://github.com/piotrwitek/utility-types
 * @example
 * ```
 * const obj = {
 *  name: "koala",
 *  sayHello() {
 *    return "grmmm";
 *  }
 * };
 * type TObjPropertyNames = PropertyNames<typeof obj>;
 * // Expect: "name" | "sayHello"
 * ```
 */
type TPropertyNames<T extends object> = {
  [K in keyof T]-?: TNonUndefined<K>;
}[keyof T];

/**
Filter out keys from an object.
Returns `never` if `Exclude` is strictly equal to `Key`.
Returns `never` if `Key` extends `Exclude`.
Returns `Key` otherwise.
@example
```
type Filtered = Filter<'foo', 'foo'>;
//=> never
```
@example
```
type Filtered = Filter<'bar', string>;
//=> never
```
@example
```
type Filtered = Filter<'bar', 'foo'>;
//=> 'bar'
```
@see {Except}
*/
type Filter<KeyType, ExcludeType> = IsEqual<KeyType, ExcludeType> extends true
  ? never
  : KeyType extends ExcludeType
  ? never
  : KeyType;

/**
Create a type from an object type without certain keys.
This type is a stricter version of [`Omit`](https://www.typescriptlang.org/docs/handbook/release-notes/typescript-3-5.html#the-omit-helper-type). The `Omit` type does not restrict the omitted keys to be keys present on the given type, while `Except` does. The benefits of a stricter type are avoiding typos and allowing the compiler to pick up on rename refactors automatically.
This type was proposed to the TypeScript team, which declined it, saying they prefer that libraries implement stricter versions of the built-in types ([microsoft/TypeScript#30825](https://github.com/microsoft/TypeScript/issues/30825#issuecomment-523668235)).
@example
```
import type {Except} from 'type-fest';
type Foo = {
	a: number;
	b: string;
	c: boolean;
};
type FooWithoutA = Except<Foo, 'a' | 'c'>;
//=> {b: string};
```
@category Object
*/
type TExcludeKeys<ObjectType, KeysType extends keyof ObjectType> = {
  [KeyType in keyof ObjectType as Filter<
    KeyType,
    KeysType
  >]: ObjectType[KeyType];
};

type TExcludeValues<T extends TDictionary, V> = Pick<
  T,
  { [K in keyof T]-?: T[K] extends V ? never : K }[keyof T]
>;

/**
 * Lookup<T, K>
 * ----
 * From an object `T`, get the type of the value of the key `K`
 * @example
 * ```
 * type Props = { readonly age: 42; readonly name: "Bob" }
 * type AgeValue = Lookup<Props, "age"> // Expected: 42
 * ```
 */
type TLookup<T, K> = K extends keyof T ? T[K] : never;

/**
 * MutableKeys<T>
 * ---
 * Get union type of keys that are mutable in object type `T`
 * @credit https://github.com/piotrwitek/utility-types
 * @author Matt McCutchen
 * https://stackoverflow.com/questions/52443276/how-to-exclude-getter-only-properties-from-type-in-typescript
 * @example
 * ```
 *   type Props = { readonly foo: string; bar: number };
 *
 *   // Expect: "bar"
 *   type Keys = MutableKeys<Props>;
 * ```
 */
type MutableKeys<T extends object> = {
  [P in keyof T]-?: IfEquals<
    { [Q in P]: T[P] },
    { -readonly [Q in P]: T[P] },
    P
  >;
}[keyof T];

