type ArrayEntry<BaseType extends readonly unknown[]> = [
  number,
  BaseType[number]
];
type TMapEntry<BaseType> = [TMapKey<BaseType>, TMapValue<BaseType>];
type TObjectEntry<BaseType> = [keyof BaseType, BaseType[keyof BaseType]];
type TSetEntry<BaseType> = BaseType extends Set<infer ItemType>
  ? [ItemType, ItemType]
  : never;

